sql:
SELECT template_name, description 
FROM templates 
ORDER BY template_name ASC;

SELECT stage_name
FROM processing_stages
WHERE stage_order <= (SELECT AVG(stage_order) FROM processing_stages);

SELECT stage_name, description 
FROM processing_stages 
WHERE stage_order BETWEEN 6 AND 9;

