sql:
SELECT stage_name, COUNT(*)
FROM processing_stages
GROUP BY stage_name;

SELECT default_size_limit
FROM default_limits
WHERE molecule_type = 'ligand';

SELECT method
FROM charge_derivation
WHERE qm0_id IN (
    SELECT qm0_id
    FROM semi_empirical_qm
);

SELECT AVG(user_count) 
FROM (
  SELECT department, COUNT(*) as user_count 
  FROM users 
  GROUP BY department
);

SELECT COUNT(*) AS count_is_500
FROM default_limits
WHERE default_size_limit = 500;

SELECT T1.stage_name, T2.template_type
FROM processing_stages AS T1
INNER JOIN templates AS T2 ON T1.default_template_id = T2.template_id;

